query:
-- Merge Bird's Opening variations
UPDATE puzzles SET openingName = "Bird's Opening" WHERE openingName IN ('Bird Opening', 'Birds Opening');

-- Merge Alekhine's Defense variations
UPDATE puzzles SET openingName = "Alekhine's Defense" WHERE openingName IN ('Alekhine Defense', 'Alekhines Defense');

-- Merge Anderson's Opening variations
UPDATE puzzles SET openingName = "Anderson's Opening" WHERE openingName IN ('Anderssens Opening', 'Anderson Opening');

-- Verify the merge
SELECT COUNT(DISTINCT openingName) as unique_openings FROM puzzles;

